import { Component, EventEmitter, Input, Output } from '@angular/core';
import { ResumeSectionTemplate } from '../../../core/models/resume.model';

@Component({
  selector: 'app-add-section-modal',
  templateUrl: './add-section-modal.component.html'
})
export class AddSectionModalComponent {
  @Input() open = false;
  @Input() templates: ResumeSectionTemplate[] = [];
  @Output() close = new EventEmitter<void>();
  @Output() add = new EventEmitter<ResumeSectionTemplate>();
}
<div *ngIf="open" class="shell-card p-5">
  <div class="flex items-start justify-between gap-3">
    <div>
      <p class="eyebrow">Add Content</p>
      <h3 class="mt-2 text-2xl font-extrabold text-[#17172b]">Available section templates</h3>
    </div>
    <button class="btn-secondary px-3 py-2 text-sm" type="button" (click)="close.emit()">Close</button>
  </div>

  <div class="mt-5 grid gap-4 md:grid-cols-2">
    <article *ngFor="let template of templates" class="rounded-[24px] border border-[#e4e7f6] bg-[#f8f9ff] p-4">
      <div class="flex items-start justify-between gap-3">
        <div>
          <p class="text-sm font-bold text-[#17172b]">{{ template.title }}</p>
          <p class="mt-2 text-sm leading-6 text-[#667085]">{{ template.description }}</p>
        </div>
        <span class="rounded-full px-3 py-1.5 text-xs font-bold" [ngClass]="template.isPremium ? 'bg-[#fff0f0] text-[#ef4444]' : 'bg-[#ecfdf3] text-[#16a34a]'">
          {{ template.isPremium ? 'Premium' : 'Free' }}
        </span>
      </div>
      <button class="btn-primary mt-4 w-full text-sm" type="button" (click)="add.emit(template)">Add Section</button>
    </article>
  </div>
</div>
